"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["548700"],{893114(e){e.exports=JSON.parse('{"tag":{"label":"teleportation","permalink":"/dst-api-webdocs/docs/tags/teleportation","allTagsPath":"/dst-api-webdocs/docs/tags","count":11,"items":[{"id":"game-scripts/prefabs/diviningrod","title":"Diviningrod","description":"Tracks proximity to teleportato components and updates description, sound, and visual feedback when equipped by a player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/diviningrod"},{"id":"game-scripts/prefabs/diviningrodbase","title":"Diviningrodbase","description":"Acts as a base component for the divining rod that manages its state (locked/unlocked/stuck), visual states, and sound effects in coordination with the Teleportato.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/diviningrodbase"},{"id":"game-scripts/prefabs/pocketwatch_portal","title":"Pocketwatch Portal","description":"Manages the creation and lifecycle of pocketwatch-based teleportation portals, including marking recall points and spawning portal entrance/exit pairs for inter- and intra-world travel.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pocketwatch_portal"},{"id":"game-scripts/components/recallmark","title":"Recallmark","description":"Marks a specific world position as a recall point for teleportation, storing coordinates and shard ID for later use.","permalink":"/dst-api-webdocs/docs/game-scripts/components/recallmark"},{"id":"game-scripts/prefabs/retrofit_archiveteleporter","title":"Retrofit Archiveteleporter","description":"A utility prefab used to generate and link a pair of teleporter wormholes in the Blue Forest region or at a specified location, replacing an existing marker entity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/retrofit_archiveteleporter"},{"id":"game-scripts/stategraphs/SGoceanshadowcreature","title":"Sgoceanshadowcreature","description":"State machine controller for the Ocean Shadow Creature entity, managing movement, teleportation, combat states, and despawning behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGoceanshadowcreature"},{"id":"game-scripts/prefabs/telebase","title":"Telebase","description":"Manages a structure that accepts gem placements to enable teleportation functionality, and responds to hammering by destroying itself and dropping gems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/telebase"},{"id":"game-scripts/prefabs/townportal","title":"Townportal","description":"Manages the town portal structure, including channeling activation, inter-portal linking, teleportation, and dismantling behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/townportal"},{"id":"game-scripts/prefabs/vault_teleporter","title":"Vault Teleporter","description":"Manages teleportation behavior and state for the Vault Teleporter structure, including channeling, hauntable interactions, and visual/animation states based on power and construction status.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_teleporter"},{"id":"game-scripts/prefabs/winona_teleport_pad","title":"Winona Teleport Pad","description":"Manages construction, power state, circuit connectivity, and teleportation power consumption for the Winona teleport pad structure.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winona_teleport_pad"},{"id":"game-scripts/prefabs/wortox","title":"Wortox","description":"Defines the Wortox character prefab with soul collection mechanics, portal hopping abilities, inclination system, overload management, buff and debuff systems including soul echo and panflute, decoy functionality, and extensive event-driven gameplay systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wortox"}],"unlisted":false}}')}}]);